use autocomplete_protocol::{PROTOCOL_VERSION, schema};
use std::env;
use std::fs;
use std::path::PathBuf;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let output_dir = env::args_os()
        .nth(1)
        .map(PathBuf::from)
        .unwrap_or_else(|| PathBuf::from("clients/protocol/src/generated"));

    fs::create_dir_all(&output_dir)?;
    schema::export_schema_files(output_dir.join("schemas"))?;
    fs::write(output_dir.join("protocol-v1.js"), protocol_js())?;

    Ok(())
}

fn protocol_js() -> String {
    format!(
        r#""use strict";
// @generated by `cargo run -p autocomplete-protocol --bin export_client_artifacts -- <output-dir>`.
// Source of truth: crates/autocomplete-protocol.

module.exports = Object.freeze({{
  PROTOCOL_VERSION: {protocol_version},
  HEALTH_PATH: "/health",
  AUTOCOMPLETE_PATH: "/v1/autocomplete",
  CANCEL_PATH_PREFIX: "/v1/cancel/",
  RELOAD_PATH: "/v1/reload",
  AUTOCOMPLETE_MODE_INLINE_TAB: "inline_tab",
  TRIGGER_IDLE: "idle",
  TRIGGER_MANUAL: "manual",
  TRIGGER_DOCUMENT_CHANGE: "document_change",
  RESPONSE_OK: "ok",
  RESPONSE_NO_SUGGESTION: "no_suggestion",
  RESPONSE_CANCELLED: "cancelled",
  RESPONSE_ERROR: "error"
}});
"#,
        protocol_version = PROTOCOL_VERSION
    )
}
